import { execSync } from "child_process"
import { readFileSync, readdirSync, statSync, writeFileSync, existsSync } from "fs"
import { join } from "path"

const platform = process.argv[2]
const tag = process.argv[3]
const repo = process.argv[4]
const bundleType = process.argv[5]

const version = tag.replace(/^v/, "")
const baseUrl = `https://github.com/${repo}/releases/download/${tag}`

// Find the updater artifact (tar.gz for macos, exe for nsis, AppImage for linux)
function findArtifact(dir, ext) {
  try {
    for (const item of readdirSync(dir)) {
      const full = join(dir, item)
      if (statSync(full).isDirectory()) {
        const found = findArtifact(full, ext)
        if (found) return found
      } else if (item.endsWith(ext)) {
        return full
      }
    }
  } catch {}
  return null
}

// Search for the updater artifact in bundle directories
const searchDirs = []
if (bundleType) {
  searchDirs.push(
    `src-tauri/target/release/bundle/${bundleType}`,
    `src-tauri/target/aarch64-apple-darwin/release/bundle/${bundleType}`,
  )
}
searchDirs.push(
  "src-tauri/target/release/bundle",
  "src-tauri/target/aarch64-apple-darwin/release/bundle",
)

// Determine artifact extension
const extMap = { macos: ".tar.gz", nsis: ".exe", appimage: ".AppImage" }
const artifactExt = extMap[bundleType] || ".tar.gz"

let artifactFile = null
for (const d of searchDirs) {
  artifactFile = findArtifact(d, artifactExt)
  if (artifactFile) break
}

if (!artifactFile) {
  console.error(`No updater artifact (*${artifactExt}) found`)
  process.exit(1)
}

const artifactName = artifactFile.split(/[/\\]/).pop()
const sigFile = artifactFile + ".sig"
let sigContent = ""

if (existsSync(sigFile)) {
  // Signature already generated by Tauri build
  sigContent = readFileSync(sigFile, "utf8").trim()
  console.log("Using existing .sig file")
} else {
  // Generate signature using tauri signer
  const privKey = process.env.TAURI_SIGNING_PRIVATE_KEY
  const privKeyPassword = process.env.TAURI_SIGNING_KEY_PASSWORD || ""
  if (!privKey) {
    console.error("TAURI_SIGNING_PRIVATE_KEY not set, cannot sign")
    process.exit(1)
  }
  console.log("Signing artifact...")
  const cmd = `npx tauri signer sign --private-key "${privKey}" --password "${privKeyPassword}" "${artifactFile}"`
  execSync(cmd, { stdio: "inherit" })
  sigContent = readFileSync(sigFile, "utf8").trim()
  console.log("Signature generated")
}

writeFileSync("latest.json", JSON.stringify({
  version,
  notes: "",
  pub_date: new Date().toISOString(),
  platforms: { [platform]: { signature: sigContent, url: `${baseUrl}/${artifactName}` } },
}, null, 2) + "\n")

console.log(`Generated latest.json for ${platform}: ${artifactName}`)
